const fs = require('fs');
const path = require('path');
const zlib = require('zlib');

// Read docx as zip using built-in modules
const filepath = 'C:\\\\Users\\\\hara\\\\OneDrive\\\\デスクトップ\\\\湯割り革命.docx';
const buf = fs.readFileSync(filepath);

// Find document.xml in the zip - minimal zip parser
let offset = 0;
const entries = [];
while (offset < buf.length - 4) {
  if (buf.readUInt32LE(offset) === 0x04034b50) { // Local file header
    const fnLen = buf.readUInt16LE(offset + 26);
    const extraLen = buf.readUInt16LE(offset + 28);
    const compSize = buf.readUInt32LE(offset + 18);
    const method = buf.readUInt16LE(offset + 8);
    const fn = buf.toString('utf8', offset + 30, offset + 30 + fnLen);
    const dataStart = offset + 30 + fnLen + extraLen;
    entries.push({ name: fn, method, dataStart, compSize });
    offset = dataStart + compSize;
  } else {
    break;
  }
}

entries.forEach(e => console.log(e.name));

// Extract word/document.xml
const docEntry = entries.find(e => e.name === 'word/document.xml');
if (docEntry) {
  const raw = buf.slice(docEntry.dataStart, docEntry.dataStart + docEntry.compSize);
  let content;
  if (docEntry.method === 8) { // Deflate
    content = zlib.inflateRawSync(raw).toString('utf8');
  } else {
    content = raw.toString('utf8');
  }
  // Extract text
  const texts = [];
  content.replace(/<w:t[^>]*>([^<]*)<\\/w:t>/g, (m, t) => texts.push(t));
  console.log('\\n=== DOCUMENT TEXT ===');
  console.log(texts.join(''));
}
