(async () => {
  const resp = await fetch('http://127.0.0.1:18923/wbs.xlsx');
  const blob = await resp.blob();
  const file = new File([blob], '\u6e6f\u5272\u308a\u9769\u547d_WBS.xlsx', {
    type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
  });

  const iframe = document.querySelectorAll('iframe')[7];
  const fileInput = iframe.contentDocument.querySelector('input[type="file"]');

  const dt = new DataTransfer();
  dt.items.add(file);
  fileInput.files = dt.files;

  fileInput.dispatchEvent(new Event('change', { bubbles: true }));

  return 'File set: ' + file.name + ' (' + file.size + ' bytes)';
})();
